#include "biblia.h"

void Biblia::CarregarTiago(Biblia* b) {
    b->dados[TIAGO].nome = wxT("Tiago");

    b->dados[TIAGO].capitulos[1].versos[1] = wxT("Tiago, servo de Deus e do Senhor Jesus Cristo, às doze tribos da Dispersão, saúde.");
    b->dados[TIAGO].capitulos[1].versos[2] = wxT("Meus irmãos, tende por motivo de grande gozo o passardes por várias provações,");
    b->dados[TIAGO].capitulos[1].versos[3] = wxT("sabendo que a aprovação da vossa fé produz a perseverança;");
    b->dados[TIAGO].capitulos[1].versos[4] = wxT("e a perseverança tenha a sua obra perfeita, para que sejais perfeitos e completos, não faltando em coisa alguma.");
    b->dados[TIAGO].capitulos[1].versos[5] = wxT("Ora, se algum de vós tem falta de sabedoria, peça-a a Deus, que a todos dá liberalmente e não censura, e ser-lhe-á dada.");
    b->dados[TIAGO].capitulos[1].versos[6] = wxT("Peça-a, porém, com fé, não duvidando; pois aquele que duvida é semelhante à onda do mar, que é sublevada e agitada pelo vento.");
    b->dados[TIAGO].capitulos[1].versos[7] = wxT("Não pense tal homem que receberá do Senhor alguma coisa,");
    b->dados[TIAGO].capitulos[1].versos[8] = wxT("homem vacilante que é, e inconstante em todos os seus caminhos.");
    b->dados[TIAGO].capitulos[1].versos[9] = wxT("Mas o irmão de condição humilde glorie-se na sua exaltação,");
    b->dados[TIAGO].capitulos[1].versos[10] = wxT("e o rico no seu abatimento; porque ele passará como a flor da erva.");
    b->dados[TIAGO].capitulos[1].versos[11] = wxT("Pois o sol se levanta em seu ardor e faz secar a erva; a sua flor cai e a beleza do seu aspecto perece; assim murchará também o rico em seus caminhos.");
    b->dados[TIAGO].capitulos[1].versos[12] = wxT("Bem-aventurado o homem que suporta a provação; porque, depois de aprovado, receberá a coroa da vida, que o Senhor prometeu aos que o amam.");
    b->dados[TIAGO].capitulos[1].versos[13] = wxT("Ninguém, sendo tentado, diga: Sou tentado por Deus; porque Deus não pode ser tentado pelo mal e ele a ninguém tenta.");
    b->dados[TIAGO].capitulos[1].versos[14] = wxT("Cada um, porém, é tentado, quando atraído e engodado pela sua própria concupiscência;");
    b->dados[TIAGO].capitulos[1].versos[15] = wxT("então a concupiscência, havendo concebido, dá à luz o pecado; e o pecado, sendo consumado, gera a morte.");
    b->dados[TIAGO].capitulos[1].versos[16] = wxT("Não vos enganeis, meus amados irmãos.");
    b->dados[TIAGO].capitulos[1].versos[17] = wxT("Toda boa dádiva e todo dom perfeito vêm do alto, descendo do Pai das luzes, em quem não há mudança nem sombra de variação.");
    b->dados[TIAGO].capitulos[1].versos[18] = wxT("Segundo a sua própria vontade, ele nos gerou pela palavra da verdade, para que fôssemos como que primícias das suas criaturas.");
    b->dados[TIAGO].capitulos[1].versos[19] = wxT("Sabei isto, meus amados irmãos: Todo homem seja pronto para ouvir, tardio para falar e tardio para se irar.");
    b->dados[TIAGO].capitulos[1].versos[20] = wxT("Porque a ira do homem não opera a justiça de Deus.");
    b->dados[TIAGO].capitulos[1].versos[21] = wxT("Pelo que, despojando-vos de toda sorte de imundícia e de todo vestígio do mal, recebei com mansidão a palavra em vós implantada, a qual é poderosa para salvar as vossas almas.");
    b->dados[TIAGO].capitulos[1].versos[22] = wxT("E sede cumpridores da palavra e não somente ouvintes, enganando-vos a vós mesmos.");
    b->dados[TIAGO].capitulos[1].versos[23] = wxT("Pois se alguém é ouvinte da palavra e não cumpridor, é semelhante a um homem que contempla no espelho o seu rosto natural;");
    b->dados[TIAGO].capitulos[1].versos[24] = wxT("porque se contempla a si mesmo e vai-se, e logo se esquece de como era.");
    b->dados[TIAGO].capitulos[1].versos[25] = wxT("Entretanto aquele que atenta bem para a lei perfeita, a da liberdade, e nela persevera, não sendo ouvinte esquecido, mas executor da obra, este será bem-aventurado no que fizer.");
    b->dados[TIAGO].capitulos[1].versos[26] = wxT("Se alguém cuida ser religioso e não refreia a sua língua, mas engana o seu coração, a sua religião é vã.");
    b->dados[TIAGO].capitulos[1].versos[27] = wxT("A religião pura e imaculada diante de nosso Deus e Pai é esta: Visitar os órfãos e as viúvas nas suas aflições e guardar-se isento da corrupção do mundo.");

    b->dados[TIAGO].capitulos[2].versos[1] = wxT("Meus irmãos, não tenhais a fé em nosso Senhor Jesus Cristo, Senhor da glória, em acepção de pessoas.");
    b->dados[TIAGO].capitulos[2].versos[2] = wxT("Porque, se entrar na vossa reunião algum homem com anel de ouro no dedo e com traje esplêndido, e entrar também algum pobre com traje sórdido.");
    b->dados[TIAGO].capitulos[2].versos[3] = wxT("e atentardes para o que vem com traje esplêndido e lhe disserdes: Senta-te aqui num lugar de honra; e disserdes ao pobre: Fica em pé, ou senta-te abaixo do escabelo dos meus pés,");
    b->dados[TIAGO].capitulos[2].versos[4] = wxT("não fazeis, porventura, distinção entre vós mesmos e não vos tornais juizes movidos de maus pensamentos?");
    b->dados[TIAGO].capitulos[2].versos[5] = wxT("Ouvi, meus amados irmãos. Não escolheu Deus os que são pobres quanto ao mundo para fazê-los ricos na fé e herdeiros do reino que prometeu aos que o amam?");
    b->dados[TIAGO].capitulos[2].versos[6] = wxT("Mas vós desonrastes o pobre. Porventura não são os ricos os que vos oprimem e os que vos arrastam aos tribunais?");
    b->dados[TIAGO].capitulos[2].versos[7] = wxT("Não blasfemam eles o bom nome pelo qual sois chamados?");
    b->dados[TIAGO].capitulos[2].versos[8] = wxT("Todavia, se estais cumprindo a lei real segundo a escritura: Amarás ao teu próximo como a ti mesmo, fazeis bem.");
    b->dados[TIAGO].capitulos[2].versos[9] = wxT("Mas se fazeis acepção de pessoas, cometeis pecado, sendo por isso condenados pela lei como transgressores.");
    b->dados[TIAGO].capitulos[2].versos[10] = wxT("Pois qualquer que guardar toda a lei, mas tropeçar em um só ponto, tem-se tornado culpado de todos.");
    b->dados[TIAGO].capitulos[2].versos[11] = wxT("Porque o mesmo que disse: Não adulterarás, também disse: Não matarás. Ora, se não cometes adultério, mas és homicida, te hás tornado transgressor da lei.");
    b->dados[TIAGO].capitulos[2].versos[12] = wxT("Falai de tal maneira e de tal maneira procedei, como havendo de ser julgados pela lei da liberdade.");
    b->dados[TIAGO].capitulos[2].versos[13] = wxT("Porque o juízo será sem misericórdia para aquele que não usou de misericórdia; a misericórdia triunfa sobre o juízo.");
    b->dados[TIAGO].capitulos[2].versos[14] = wxT("Que proveito há, meus irmãos se alguém disser que tem fé e não tiver obras? Porventura essa fé pode salvá-lo?");
    b->dados[TIAGO].capitulos[2].versos[15] = wxT("Se um irmão ou uma irmã estiverem nus e tiverem falta de mantimento cotidiano,");
    b->dados[TIAGO].capitulos[2].versos[16] = wxT("e algum de vós lhes disser: Ide em paz, aquentai-vos e fartai-vos; e não lhes derdes as coisas necessárias para o corpo, que proveito há nisso?");
    b->dados[TIAGO].capitulos[2].versos[17] = wxT("Assim também a fé, se não tiver obras, é morta em si mesma.");
    b->dados[TIAGO].capitulos[2].versos[18] = wxT("Mas dirá alguém: Tu tens fé, e eu tenho obras; mostra-me a tua fé sem as obras, e eu te mostrarei a minha fé pelas minhas obras.");
    b->dados[TIAGO].capitulos[2].versos[19] = wxT("Crês tu que Deus é um só? Fazes bem; os demônios também o crêem, e estremecem.");
    b->dados[TIAGO].capitulos[2].versos[20] = wxT("Mas queres saber, ó homem insensato, que a fé sem as obras é inútil?");
    b->dados[TIAGO].capitulos[2].versos[21] = wxT("Porventura não foi pelas obras que nosso pai Abraão foi justificado quando ofereceu sobre o altar seu filho Isaque?");
    b->dados[TIAGO].capitulos[2].versos[22] = wxT("Vês que a fé cooperou com as suas obras, e que pelas obras a fé foi aperfeiçoada.");
    b->dados[TIAGO].capitulos[2].versos[23] = wxT("E se cumpriu a escritura que diz: E creu Abraão em Deus, e isso lhe foi imputado como justiça, e foi chamado amigo de Deus.");
    b->dados[TIAGO].capitulos[2].versos[24] = wxT("Vedes então que é pelas obras que o homem é justificado, e não somente pela fé.");
    b->dados[TIAGO].capitulos[2].versos[25] = wxT("E de igual modo não foi a meretriz Raabe também justificada pelas obras, quando acolheu os espias, e os fez sair por outro caminho?");
    b->dados[TIAGO].capitulos[2].versos[26] = wxT("Porque, assim como o corpo sem o espírito está morto, assim também a fé sem obras é morta.");

    b->dados[TIAGO].capitulos[3].versos[1] = wxT("Meus irmãos, não sejais muitos de vós mestres, sabendo que receberemos um juízo mais severo.");
    b->dados[TIAGO].capitulos[3].versos[2] = wxT("Todos tropeçamos em muitas coisas. Se alguém não tropeça em palavra, esse é homem perfeito, e capaz de refrear também todo o corpo.");
    b->dados[TIAGO].capitulos[3].versos[3] = wxT("Ora, se pomos freios na boca dos cavalos, para que nos obedeçam, então conseguimos dirigir todo o seu corpo.");
    b->dados[TIAGO].capitulos[3].versos[4] = wxT("Vede também os navios que, embora tão grandes e levados por impetuosos ventos, com um pequenino leme se voltam para onde quer o impulso do timoneiro.");
    b->dados[TIAGO].capitulos[3].versos[5] = wxT("Assim também a língua é um pequeno membro, e se gaba de grandes coisas. Vede quão grande bosque um tão pequeno fogo incendeia.");
    b->dados[TIAGO].capitulos[3].versos[6] = wxT("A língua também é um fogo; sim, a língua, qual mundo de iniqüidade, colocada entre os nossos membros, contamina todo o corpo, e inflama o curso da natureza, sendo por sua vez inflamada pelo inferno.");
    b->dados[TIAGO].capitulos[3].versos[7] = wxT("Pois toda espécie tanto de feras, como de aves, tanto de répteis como de animais do mar, se doma, e tem sido domada pelo gênero humano,");
    b->dados[TIAGO].capitulos[3].versos[8] = wxT("mas a língua, nenhum homem a pode domar. É um mal irrefreável; está cheia de peçonha mortal.");
    b->dados[TIAGO].capitulos[3].versos[9] = wxT("Com ela bendizemos ao Senhor e Pai, e com ela amaldiçoamos os homens, feitos à semelhança de Deus.");
    b->dados[TIAGO].capitulos[3].versos[10] = wxT("Da mesma boca procede bênção e maldição. Não convém, meus irmãos, que se faça assim.");
    b->dados[TIAGO].capitulos[3].versos[11] = wxT("Porventura a fonte deita da mesma abertura água doce e água amargosa?");
    b->dados[TIAGO].capitulos[3].versos[12] = wxT("Meus irmãos, pode acaso uma figueira produzir azeitonas, ou uma videira figos? Nem tampouco pode uma fonte de água salgada dar água doce.");
    b->dados[TIAGO].capitulos[3].versos[13] = wxT("Quem dentre vós é sábio e entendido? Mostre pelo seu bom procedimento as suas obras em mansidão de sabedoria.");
    b->dados[TIAGO].capitulos[3].versos[14] = wxT("Mas, se tendes amargo ciúme e sentimento faccioso em vosso coração, não vos glorieis, nem mintais contra a verdade.");
    b->dados[TIAGO].capitulos[3].versos[15] = wxT("Essa não é a sabedoria que vem do alto, mas é terrena, animal e diabólica.");
    b->dados[TIAGO].capitulos[3].versos[16] = wxT("Porque onde há ciúme e sentimento faccioso, aí há confusão e toda obra má.");
    b->dados[TIAGO].capitulos[3].versos[17] = wxT("Mas a sabedoria que vem do alto é, primeiramente, pura, depois pacífica, moderada, tratável, cheia de misericórdia e de bons frutos, sem parcialidade, e sem hipocrisia.");
    b->dados[TIAGO].capitulos[3].versos[18] = wxT("Ora, o fruto da justiça semeia-se em paz para aqueles que promovem a paz.");

    b->dados[TIAGO].capitulos[4].versos[1] = wxT("Donde vêm as guerras e contendas entre vós? Porventura não vêm disto, dos vossos deleites, que nos vossos membros guerreiam?");
    b->dados[TIAGO].capitulos[4].versos[2] = wxT("Cobiçais e nada tendes; logo matais. Invejais, e não podeis alcançar; logo combateis e fazeis guerras. Nada tendes, porque não pedis.");
    b->dados[TIAGO].capitulos[4].versos[3] = wxT("Pedis e não recebeis, porque pedis mal, para o gastardes em vossos deleites.");
    b->dados[TIAGO].capitulos[4].versos[4] = wxT("Infiéis, não sabeis que a amizade do mundo é inimizade contra Deus? Portanto qualquer que quiser ser amigo do mundo constitui-se inimigo de Deus.");
    b->dados[TIAGO].capitulos[4].versos[5] = wxT("Ou pensais que em vão diz a escritura: O Espírito que ele fez habitar em nós anseia por nós até o ciúme?");
    b->dados[TIAGO].capitulos[4].versos[6] = wxT("Todavia, dá maior graça. Portanto diz: Deus resiste aos soberbos; dá, porém, graça aos humildes.");
    b->dados[TIAGO].capitulos[4].versos[7] = wxT("Sujeitai-vos, pois, a Deus; mas resisti ao Diabo, e ele fugirá de vós.");
    b->dados[TIAGO].capitulos[4].versos[8] = wxT("Chegai-vos para Deus, e ele se chegará para vós. Limpai as mãos, pecadores; e, vós de espírito vacilante, purificai os corações.");
    b->dados[TIAGO].capitulos[4].versos[9] = wxT("Senti as vossas misérias, lamentai e chorai; torne-se o vosso riso em pranto, e a vossa alegria em tristeza.");
    b->dados[TIAGO].capitulos[4].versos[10] = wxT("Humilhai-vos perante o Senhor, e ele vos exaltará.");
    b->dados[TIAGO].capitulos[4].versos[11] = wxT("Irmãos, não faleis mal uns dos outros. Quem fala mal de um irmão, e julga a seu irmão, fala mal da lei, e julga a lei; ora, se julgas a lei, não és observador da lei, mas juiz.");
    b->dados[TIAGO].capitulos[4].versos[12] = wxT("Há um só legislador e juiz, aquele que pode salvar e destruir; tu, porém, quem és, que julgas ao próximo?");
    b->dados[TIAGO].capitulos[4].versos[13] = wxT("E agora, vós que dizeis: Hoje ou amanhã iremos a tal cidade, lá passaremos um ano, negociaremos e ganharemos.");
    b->dados[TIAGO].capitulos[4].versos[14] = wxT("No entanto, não sabeis o que sucederá amanhã. Que é a vossa vida? Sois um vapor que aparece por um pouco, e logo se desvanece.");
    b->dados[TIAGO].capitulos[4].versos[15] = wxT("Em lugar disso, devíeis dizer: Se o Senhor quiser, viveremos e faremos isto ou aquilo.");
    b->dados[TIAGO].capitulos[4].versos[16] = wxT("Mas agora vos jactais das vossas presunções; toda jactância tal como esta é maligna.");
    b->dados[TIAGO].capitulos[4].versos[17] = wxT("Aquele, pois, que sabe fazer o bem e não o faz, comete pecado.");

    b->dados[TIAGO].capitulos[5].versos[1] = wxT("E agora, vós ricos, chorai e pranteai, por causa das desgraças que vos sobrevirão.");
    b->dados[TIAGO].capitulos[5].versos[2] = wxT("As vossas riquezas estão apodrecidas, e as vossas vestes estão roídas pela traça.");
    b->dados[TIAGO].capitulos[5].versos[3] = wxT("O vosso ouro e a vossa prata estão enferrujados; e a sua ferrugem dará testemunho contra vós, e devorará as vossas carnes como fogo. Entesourastes para os últimos dias.");
    b->dados[TIAGO].capitulos[5].versos[4] = wxT("Eis que o salário que fraudulentamente retivestes aos trabalhadores que ceifaram os vossos campos clama, e os clamores dos ceifeiros têm chegado aos ouvidos do Senhor dos exércitos.");
    b->dados[TIAGO].capitulos[5].versos[5] = wxT("Deliciosamente vivestes sobre a terra, e vos deleitastes; cevastes os vossos corações no dia da matança.");
    b->dados[TIAGO].capitulos[5].versos[6] = wxT("Condenastes e matastes o justo; ele não vos resiste.");
    b->dados[TIAGO].capitulos[5].versos[7] = wxT("Portanto, irmãos, sede pacientes até a vinda do Senhor. Eis que o lavrador espera o precioso fruto da terra, aguardando-o com paciência, até que receba as primeiras e as últimas chuvas.");
    b->dados[TIAGO].capitulos[5].versos[8] = wxT("Sede vós também pacientes; fortalecei os vossos corações, porque a vinda do Senhor está próxima.");
    b->dados[TIAGO].capitulos[5].versos[9] = wxT("Não vos queixeis, irmãos, uns dos outros, para que não sejais julgados. Eis que o juiz está à porta.");
    b->dados[TIAGO].capitulos[5].versos[10] = wxT("Irmãos, tomai como exemplo de sofrimento e paciência os profetas que falaram em nome do Senhor.");
    b->dados[TIAGO].capitulos[5].versos[11] = wxT("Eis que chamamos bem-aventurados os que suportaram aflições. Ouvistes da paciência de Jó, e vistes o fim que o Senhor lhe deu, porque o Senhor é cheio de misericórdia e compaixão.");
    b->dados[TIAGO].capitulos[5].versos[12] = wxT("Mas, sobretudo, meus irmãos, não jureis, nem pelo céu, nem pela terra, nem façais qualquer outro juramento; seja, porém, o vosso sim, sim, e o vosso não, não, para não cairdes em condenação.");
    b->dados[TIAGO].capitulos[5].versos[13] = wxT("Está aflito alguém entre vós? Ore. Está alguém contente? Cante louvores.");
    b->dados[TIAGO].capitulos[5].versos[14] = wxT("Está doente algum de vós? Chame os anciãos da igreja, e estes orem sobre ele, ungido-o com óleo em nome do Senhor;");
    b->dados[TIAGO].capitulos[5].versos[15] = wxT("e a oração da fé salvará o doente, e o Senhor o levantará; e, se houver cometido pecados, ser-lhe-ão perdoados.");
    b->dados[TIAGO].capitulos[5].versos[16] = wxT("Confessai, portanto, os vossos pecados uns aos outros, e orai uns pelos outros, para serdes curados. A súplica de um justo pode muito na sua atuação.");
    b->dados[TIAGO].capitulos[5].versos[17] = wxT("Elias era homem sujeito às mesmas paixões que nós, e orou com fervor para que não chovesse, e por três anos e seis meses não choveu sobre a terra.");
    b->dados[TIAGO].capitulos[5].versos[18] = wxT("E orou outra vez e o céu deu chuva, e a terra produziu o seu fruto.");
    b->dados[TIAGO].capitulos[5].versos[19] = wxT("Meus irmãos, se alguém dentre vós se desviar da verdade e alguém o converter,");
    b->dados[TIAGO].capitulos[5].versos[20] = wxT("sabei que aquele que fizer converter um pecador do erro do seu caminho salvará da morte uma alma, e cobrirá uma multidão de pecados.");

}
